function determineConfidence(
  ratio: number,
  coOccurringPatterns: string[],
  astLevel: boolean,
  hasConflict = false,
): ForensicAssertion["confidence"] {
  if (hasConflict) { return "LOW"; }
  if (astLevel) { return "HIGH"; }
  if (ratio < 0.5) { return "LOW"; }
  if (ratio >= 0.8 && coOccurringPatterns.length >= 2) { return "HIGH"; }
  return "MEDIUM";
}

